import React, { useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function About(){
    const navigate=useNavigate();
    <div>
        <h1>About ManorMadhu</h1>
        <p>Diabetes Tracker is a web application designed to help users monitor their daily food intake and make informed dietary choices. The application provides nutritional information for homemade and packaged foods, allowing users to track their carbohydrate and calorie intake. Based on the foods consumed, the system offers personalized dietary recommendations to support healthier eating habits.</p> 
        <h2> Our Objective key features include:</h2>
        <ul>
            <li>Help users monitor their daily food consumption.</li>
            <li>Increase awareness of carbohydrate and calorie intake.</li>
            <li>Encourage healthier food choices through personalized recommendations.</li>
            <li>Simplify food tracking using an easy-to-use interface.</li>
        </ul>
    </div>
}
export default About;
